# ═══════════════════════════════════════════════════════════
# Memory Consolidator API
# ═══════════════════════════════════════════════════════════

from agent.shared import memory_consolidator, ConsolidationStrategy, MemoryImportance


class StoreMemoryRequest(BaseModel):
    content: str
    importance: str = "medium"
    tags: list[str] = Field(default_factory=list)
    layer: str = "episodic"
    memory_type: str = "episodic"
    source_session: str = ""


class SearchMemoryRequest(BaseModel):
    query: str
    memory_type: str | None = None
    limit: int = 10


class ConsolidateMemoryRequest(BaseModel):
    strategy: str = "summarize"
    target_layer: str = "episodic"
    limit: int = 50


@router.get("/memory-consolidator/stats")
async def get_memory_consolidator_stats():
    """Get memory consolidator statistics."""
    return memory_consolidator.get_stats()


@router.post("/memory-consolidator/store")
async def store_memory(data: StoreMemoryRequest):
    """Store a memory entry."""
    importance = MemoryImportance(data.importance)
    layer = data.memory_type or data.layer
    if layer == "episodic":
        entry = memory_consolidator.store_episodic(
            content=data.content,
            importance=importance,
            tags=data.tags,
        )
    elif layer == "semantic":
        entry = memory_consolidator.store_semantic(
            content=data.content,
            importance=importance,
            tags=data.tags,
        )
    elif layer == "procedural":
        entry = memory_consolidator.store_procedural(
            content=data.content,
            importance=importance,
            tags=data.tags,
        )
    else:
        raise HTTPException(400, f"Invalid layer: {layer}")
    return {
        "entry_id": entry.entry_id,
        "layer": entry.layer,
        "memory_type": entry.layer,
        "importance": entry.importance.value,
        "tags": entry.tags,
        "content": data.content[:200],
        "source_session": data.source_session,
        "access_count": getattr(entry, 'access_count', 0),
        "last_accessed": getattr(entry, 'last_accessed', ''),
        "created_at": getattr(entry, 'created_at', ''),
    }


@router.get("/memory-consolidator/search")
async def search_memories(query: str, layer: str | None = None, limit: int = 10):
    """Search memories."""
    results = memory_consolidator.search(query=query, layer=layer, limit=limit)
    return {
        "results": [
            {
                "entry_id": e.entry_id,
                "layer": e.layer,
                "content": e.content[:200],
                "importance": e.importance.value,
                "access_count": e.access_count,
                "tags": e.tags,
            }
            for e in results
        ]
    }


@router.post("/memory-consolidator/consolidate")
async def consolidate_memories(data: ConsolidateMemoryRequest = Body(default=ConsolidateMemoryRequest())):
    """Consolidate memories."""
    strategy = data.strategy
    layer = data.target_layer
    strat = ConsolidationStrategy(strategy)
    results = memory_consolidator.consolidate(strategy=strat, target_layer=layer)
    return {
        "consolidated": [
            {
                "consolidated_id": cm.memory_id if hasattr(cm, 'memory_id') else '',
                "summary": cm.summary[:200] if hasattr(cm, 'summary') else '',
                "source_entries": getattr(cm, 'source_entries', []),
                "strategy": cm.consolidation_strategy.value if hasattr(cm, 'consolidation_strategy') else strategy,
                "quality_score": getattr(cm, 'quality_score', 0.5),
                "entry_count": cm.source_count if hasattr(cm, 'source_count') else 0,
                "created_at": getattr(cm, 'created_at', ''),
            }
            for cm in results
        ]
    }


@router.post("/memory-consolidator/decay")
async def apply_memory_decay(data: dict = Body(default={})):
    """Apply memory decay check."""
    threshold = data.get("threshold", 0.1)
    result = memory_consolidator.check_decay(threshold=threshold)
    return {"removed": result.get("removed", 0) if isinstance(result, dict) else 0}


@router.get("/memory-consolidator/concept-map")
async def get_concept_map():
    """Get concept-to-entry mapping."""
    return {"concept_map": memory_consolidator.get_concept_map()}


# ═══════════════════════════════════════════════════════════
# Context Compressor API
# ═══════════════════════════════════════════════════════════

from agent.shared import context_compressor, CompressionStrategy, ContentPriority


class AddContextChunkRequest(BaseModel):
    content: str
    role: str = "user"
    priority: str = "background"
    importance: float = 0.5
    source: str = ""


class CompressContextRequest(BaseModel):
    strategy: str = "hierarchical"
    target_tokens: int | None = None


class SetBudgetRequest(BaseModel):
    max_tokens: int
    auto_compress: bool = True


@router.get("/context-compressor/stats")
async def get_context_compressor_stats():
    """Get context compressor statistics."""
    return context_compressor.get_stats()


@router.post("/context-compressor/chunks")
async def add_context_chunk(data: AddContextChunkRequest):
    """Add a chunk to the context."""
    priority = ContentPriority(data.priority)
    chunk = context_compressor.add_chunk(
        content=data.content,
        role=data.role,
        priority=priority,
        importance=data.importance,
    )
    return {
        "chunk_id": chunk.chunk_id,
        "token_count": chunk.token_count,
        "priority": chunk.priority.value,
        "source": data.source,
        "content": data.content[:200],
        "created_at": chunk.created_at if hasattr(chunk, 'created_at') else "",
    }


@router.post("/context-compressor/compress")
async def compress_context(data: CompressContextRequest = Body(default=CompressContextRequest())):
    """Compress the context."""
    strategy = data.strategy
    target_tokens = data.target_tokens
    strat = CompressionStrategy(strategy)
    result = context_compressor.compress(strategy=strat, target_tokens=target_tokens)
    return {
        "compression_id": getattr(result, 'compression_id', ''),
        "original_chunks": result.original_chunks,
        "compressed_chunks": result.compressed_chunks,
        "original_tokens": result.original_tokens,
        "compressed_tokens": result.compressed_tokens,
        "compression_ratio": result.compression_ratio,
        "tokens_saved": result.original_tokens - result.compressed_tokens,
        "strategy": result.strategy.value,
        "summary": result.summary,
        "duration_ms": result.duration_ms,
        "created_at": getattr(result, 'created_at', ''),
    }


@router.get("/context-compressor/context")
async def get_context(max_tokens: int | None = None):
    """Get current context with budget information."""
    messages = context_compressor.get_context(max_tokens=max_tokens)
    budget = context_compressor.get_token_budget() if hasattr(context_compressor, 'get_token_budget') else {
        "max_tokens": getattr(context_compressor, '_token_budget', 4096),
        "current_tokens": sum(len(m.get("content", "")) // 4 for m in messages),
        "remaining": 0,
        "usage_percent": 0,
        "auto_compress": True,
    }
    if isinstance(budget, dict):
        budget["remaining"] = budget.get("max_tokens", 4096) - budget.get("current_tokens", 0)
        budget["usage_percent"] = round((budget.get("current_tokens", 0) / max(budget.get("max_tokens", 1), 1)) * 100, 1)
    return {
        "chunks": [
            {
                "chunk_id": m.get("chunk_id", ""),
                "content": m.get("content", ""),
                "priority": m.get("priority", "background"),
                "source": m.get("source", ""),
                "token_count": m.get("token_count", 0),
                "created_at": m.get("created_at", ""),
            }
            for m in messages
        ],
        "budget": budget,
        "count": len(messages),
    }


@router.post("/context-compressor/clear")
async def clear_context():
    """Clear all context."""
    context_compressor.clear()
    return {"success": True}


@router.put("/context-compressor/budget")
async def set_context_budget(data: SetBudgetRequest):
    """Set token budget."""
    context_compressor.set_token_budget(data.max_tokens)
    return {
        "max_tokens": data.max_tokens,
        "auto_compress": data.auto_compress,
        "current_tokens": 0,
        "remaining": data.max_tokens,
        "usage_percent": 0.0,
    }


# ── Agent Command Center API ──

class CommandCenterRequest(BaseModel):
    agent_id: str | None = None


@router.get("/command-center/status")
async def get_command_center_status(agent_id: str | None = None):
    """Get unified command center status across all agent subsystems."""
    status_data = {
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "agent_id": agent_id,
        "subsystems": {},
    }

    # Goal Decomposer
    try:
        from agent.shared import goal_decomposer
        gd_stats = goal_decomposer.get_stats()
        status_data["subsystems"]["goal_decomposer"] = {
            "status": "active",
            "total_decompositions": gd_stats.get("total_decompositions", 0),
            "active_trees": gd_stats.get("active_goal_trees", 0),
            "completed_trees": gd_stats.get("completed_goal_trees", 0),
        }
    except Exception as e:
        status_data["subsystems"]["goal_decomposer"] = {"status": "error", "message": str(e)}

    # Self-Reflection
    try:
        from agent.shared import self_reflection_engine
        sr_stats = self_reflection_engine.get_stats()
        status_data["subsystems"]["self_reflection"] = {
            "status": "active",
            "total_sessions": sr_stats.get("total_sessions", 0),
            "active_sessions": sr_stats.get("active_sessions", 0),
            "total_insights": sr_stats.get("total_insights", 0),
        }
    except Exception as e:
        status_data["subsystems"]["self_reflection"] = {"status": "error", "message": str(e)}

    # Memory Consolidator
    try:
        from agent.shared import memory_consolidator
        mc_stats = memory_consolidator.get_stats()
        status_data["subsystems"]["memory_consolidator"] = {
            "status": "active",
            "episodic": mc_stats.get("episodic_count", 0),
            "semantic": mc_stats.get("semantic_count", 0),
            "procedural": mc_stats.get("procedural_count", 0),
        }
    except Exception as e:
        status_data["subsystems"]["memory_consolidator"] = {"status": "error", "message": str(e)}

    # Context Compressor
    try:
        from agent.shared import context_compressor
        cc_stats = context_compressor.get_stats()
        status_data["subsystems"]["context_compressor"] = {
            "status": "active",
            "total_chunks": cc_stats.get("total_chunks", 0),
            "total_compressions": cc_stats.get("total_compressions", 0),
            "tokens_saved": cc_stats.get("total_tokens_saved", 0),
        }
    except Exception as e:
        status_data["subsystems"]["context_compressor"] = {"status": "error", "message": str(e)}

    # Governance
    try:
        from agent.shared import governance_engine
        gov_stats = governance_engine.get_stats()
        status_data["subsystems"]["governance"] = {
            "status": "active",
            "policies": gov_stats.get("total_server_policies", 0) + gov_stats.get("total_agent_policies", 0),
            "pending_approvals": gov_stats.get("pending_approvals", 0),
        }
    except Exception as e:
        status_data["subsystems"]["governance"] = {"status": "error", "message": str(e)}

    # Smart Router
    try:
        from agent.shared import smart_router
        sr_stats = smart_router.get_stats()
        status_data["subsystems"]["smart_router"] = {
            "status": "active",
            "total_models": sr_stats.get("total_models", 0),
            "total_decisions": sr_stats.get("total_decisions", 0),
        }
    except Exception as e:
        status_data["subsystems"]["smart_router"] = {"status": "error", "message": str(e)}

    # Identity Core
    try:
        from agent.shared import identity_registry
        identity_stats = identity_registry.get_stats()
        status_data["subsystems"]["identity_core"] = {
            "status": "active",
            "total_identities": identity_stats.get("total_identities", 0),
        }
    except Exception as e:
        status_data["subsystems"]["identity_core"] = {"status": "error", "message": str(e)}

    # Workspace Manager
    try:
        from agent.shared import workspace_manager
        ws_stats = workspace_manager.get_stats()
        status_data["subsystems"]["workspace_manager"] = {
            "status": "active",
            "total_workspaces": ws_stats.get("total_workspaces", 0),
        }
    except Exception as e:
        status_data["subsystems"]["workspace_manager"] = {"status": "error", "message": str(e)}

    # Agent Mesh
    try:
        from agent.shared import agent_mesh
        mesh_status = agent_mesh.get_mesh_status()
        status_data["subsystems"]["agent_mesh"] = {
            "status": "active",
            "total_nodes": mesh_status.get("total_nodes", 0),
            "healthy_nodes": mesh_status.get("healthy_nodes", 0),
        }
    except Exception as e:
        status_data["subsystems"]["agent_mesh"] = {"status": "error", "message": str(e)}

    # Learning Loop
    try:
        from agent.shared import learning_loop
        ll_status = learning_loop.get_status()
        status_data["subsystems"]["learning_loop"] = {
            "status": "active",
            "observations": ll_status.get("observation", {}).get("total_observations", 0),
            "patterns": ll_status.get("extraction", {}).get("total_patterns", 0),
        }
    except Exception as e:
        status_data["subsystems"]["learning_loop"] = {"status": "error", "message": str(e)}

    # Persona
    try:
        from agent.shared import persona_registry
        persona_stats = persona_registry.get_stats()
        status_data["subsystems"]["persona"] = {
            "status": "active",
            "total_personas": persona_stats.get("total_personas", 0),
        }
    except Exception as e:
        status_data["subsystems"]["persona"] = {"status": "error", "message": str(e)}

    # Count active subsystems
    active_count = sum(
        1 for s in status_data["subsystems"].values()
        if s.get("status") == "active"
    )
    error_count = sum(
        1 for s in status_data["subsystems"].values()
        if s.get("status") == "error"
    )
    status_data["summary"] = {
        "total_subsystems": len(status_data["subsystems"]),
        "active_subsystems": active_count,
        "error_subsystems": error_count,
        "overall_status": "healthy" if error_count == 0 else "degraded" if error_count < len(status_data["subsystems"]) // 2 else "critical",
    }

    # Unified Agent System
    try:
        from agent.shared import unified_system
        us_stats = unified_system.get_stats()
        status_data["subsystems"]["unified_system"] = {
            "status": "active",
            "total_executions": us_stats.get("total_executions", 0),
            "active_sessions": us_stats.get("active_sessions", 0),
            "total_insights": us_stats.get("total_insights", 0),
        }
    except Exception as e:
        status_data["subsystems"]["unified_system"] = {"status": "error", "message": str(e)}

    # Knowledge Fabric
    try:
        from agent.shared import knowledge_fabric
        kf_stats = knowledge_fabric.get_stats()
        status_data["subsystems"]["knowledge_fabric"] = {
            "status": "active",
            "total_nodes": kf_stats.get("total_nodes", 0),
            "total_edges": kf_stats.get("total_edges", 0),
            "total_clusters": kf_stats.get("total_clusters", 0),
        }
    except Exception as e:
        status_data["subsystems"]["knowledge_fabric"] = {"status": "error", "message": str(e)}

    # Collaborative Intelligence
    try:
        from agent.shared import collaborative_intelligence
        ci_stats = collaborative_intelligence.get_stats()
        status_data["subsystems"]["collaborative_intelligence"] = {
            "status": "active",
            "total_sessions": ci_stats.get("total_sessions", 0),
            "active_sessions": ci_stats.get("active_sessions", 0),
            "registered_agents": ci_stats.get("registered_agents", 0),
        }
    except Exception as e:
        status_data["subsystems"]["collaborative_intelligence"] = {"status": "error", "message": str(e)}

    return status_data


